export async function createDependency(productId: string, title: string): Promise<PmDependency> {
  const { data, error } = await (appSchema() as any).from('activity').insert({ entity_schema: 'pim', entity_table: 'product', entity_id: productId, action: 'pm_dependency', payload: opPayload('dependency', productId, { title, dependency_type: 'blocked_by', status: 'open' }) }).select('*').single()
