  const updated = unwrap<any>({ data: result.data, error: result.error })
  return { id, product: updated.entity_id, depends_on_product: null, project: null, title: payload.title ?? null, dependency_type: payload.dependency_type ?? 'blocked_by', status, waiting_on: payload.waiting_on ?? null, due_at: payload.due_at ?? null, resolved_at: payload.resolved_at ?? null, notes: payload.notes ?? null, source_system: 'supabase', source_id: id }
}

